 &lt;p&gt;多次提交&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://fastly.jsdelivr.net/gh/iniwym/Github-Img/img/202204061220417.png&#34; alt=&#34;image-20220406120830674&#34; /&gt;&lt;/p&gt;
&lt;p&gt;初始化仓库&lt;/p&gt;
&lt;p&gt;重新上传&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;rm -rf .git

git init

git checkout --orphan main

git add .

git commit -m &amp;quot;Initial commit&amp;quot;

git remote add origin git@GitHub163:iniwym/iniwym.github.io.git

#git push -u origin main

git push -f origin main

&lt;/code&gt;&lt;/pre&gt;
